import { Component, Inject, OnInit } from '@angular/core';
import { MAT_DIALOG_DATA, MatDialogRef } from '@angular/material/dialog';
import { MatSnackBar } from '@angular/material/snack-bar';
import { firstValueFrom } from 'rxjs';
import { TrackingService } from '../../../helpers/services/tracking.service';
import { BOX_ROUTES, boxRouteLabel, legTypeForBox } from '../helpers/sample.status';

export interface BoxGroupDialogData {
  selectedSampleIds: number[];
}

@Component({
  selector: 'sample-box-group-dialog',
  standalone: false,
  templateUrl: './box-group-dialog.component.html',
  styleUrls: ['./box-group-dialog.component.scss']
})
export class BoxGroupDialogComponent implements OnInit {
  boxes: any[] = [];
  groups: any[] = [];
  changed = false;

  routes = BOX_ROUTES;
  boxRouteLabel = boxRouteLabel;

  // New box: the user picks a route; direction/from/to are derived from it.
  newBox: any = { box_label: '', route: 'ningbo_to_nyc', tracking_number: '', status: 'packing' };
  newGroup: any = { group_name: '', factory_id_fk: null, status: 'open' };

  targetBoxId: number | null = null;

  constructor(
    public dialogRef: MatDialogRef<BoxGroupDialogComponent>,
    @Inject(MAT_DIALOG_DATA) public data: BoxGroupDialogData,
    private tracking: TrackingService,
    private snackBar: MatSnackBar
  ) {}

  ngOnInit(): void {
    this.loadBoxes();
    this.loadGroups();
  }

  get selectedCount(): number { return (this.data.selectedSampleIds || []).length; }

  async loadBoxes(): Promise<void> {
    try { this.boxes = (await firstValueFrom(this.tracking.getSampleBoxes()) as any) || []; }
    catch { this.boxes = []; }
  }
  async loadGroups(): Promise<void> {
    try { this.groups = (await firstValueFrom(this.tracking.getSampleGroups()) as any) || []; }
    catch { this.groups = []; }
  }

  async createBox(): Promise<void> {
    const route = this.routes.find(r => r.value === this.newBox.route) || this.routes[0];
    const payload = {
      box_label: this.newBox.box_label || null,
      tracking_number: this.newBox.tracking_number || null,
      status: this.newBox.status || 'packing',
      direction: route.direction,
      origin_office: route.origin,
      dest_office: route.dest
    };
    try {
      const created: any = await firstValueFrom(this.tracking.createSampleBox(payload));
      this.toast('Box created');
      this.newBox = { box_label: '', route: 'ningbo_to_nyc', tracking_number: '', status: 'packing' };
      await this.loadBoxes();
      // Preselect the new box so "add selected" is one click away.
      if (created && created.box_id_pk) this.targetBoxId = created.box_id_pk;
    } catch (e: any) { this.toast(this.errMsg(e, 'Could not create box')); }
  }

  async createGroup(): Promise<void> {
    try {
      await firstValueFrom(this.tracking.createSampleGroup({ ...this.newGroup }));
      this.toast('Factory group created');
      this.newGroup = { group_name: '', factory_id_fk: null, status: 'open' };
      await this.loadGroups();
    } catch (e: any) { this.toast(this.errMsg(e, 'Could not create group')); }
  }

  // Add the grid-selected samples to a specific box.
  async addToBox(boxId: number): Promise<void> {
    if (!boxId) { this.toast('Pick a box'); return; }
    if (!this.selectedCount) {
      this.toast('Select one or more samples in the grid first, then reopen this.');
      return;
    }
    const box = this.boxes.find(b => b.box_id_pk === boxId);
    try {
      const res: any = await firstValueFrom(
        this.tracking.addSamplesToBox(boxId, { sample_ids: this.data.selectedSampleIds, leg_type: legTypeForBox(box) })
      );
      const added = (res && res.added) ? res.added.length : 0;
      const skipped = (res && res.skipped) ? res.skipped : [];
      this.changed = this.changed || added > 0;
      let msg = `Added ${added} sample(s) to ${box?.box_label || ('Box #' + boxId)}`;
      if (skipped.length) msg += `. ${skipped.length} skipped (wrong route for this box).`;
      this.toast(msg);
      await this.loadBoxes();
    } catch (e: any) { this.toast(this.errMsg(e, 'Could not add samples to box')); }
  }

  close(): void { this.dialogRef.close(this.changed ? { changed: true } : undefined); }

  private errMsg(e: any, fallback: string): string {
    return (e && e.error && e.error.message) ? e.error.message : (e?.message || fallback);
  }
  private toast(msg: string): void { this.snackBar.open(msg, 'Dismiss', { duration: 5000 }); }
}

