import { Component } from '@angular/core';
import { MatDialogRef } from '@angular/material/dialog';
import { ORIGINS, ORIGIN_DEFAULTS, OFFICES, statusLabel, directionLabel } from '../helpers/sample.status';

// Create a new sample. Origin drives direction + initial status (server confirms).
@Component({
  selector: 'sample-create-dialog',
  standalone: false,
  templateUrl: './create-dialog.component.html',
  styleUrls: ['./create-dialog.component.scss']
})
export class CreateDialogComponent {
  origins = ORIGINS;
  offices = OFFICES;

  model: any = {
    origin: 'factory_request',
    sample_name: '',
    quantity: null,
    retail_price: null,
    fob_cost: null,
    factory_id_fk: null,
    office_location: null,
    notes: ''
  };

  constructor(public dialogRef: MatDialogRef<CreateDialogComponent>) {}

  originLabel(origin: string): string {
    const map: any = {
      factory_request: 'We request from factory',
      factory_offer: 'Factory offers to us',
      usa_bought: 'Bought in USA (send out)'
    };
    return map[origin] || origin;
  }

  get previewStatus(): string {
    const def = ORIGIN_DEFAULTS[this.model.origin];
    return def ? `${statusLabel(def.initialStatus)} (${directionLabel(def.direction)})` : '';
  }

  save(): void {
    if (!this.model.origin) return;
    this.dialogRef.close({ ...this.model });
  }

  cancel(): void { this.dialogRef.close(); }
}

