  templateUrl: './factory.component.html',
  styleUrls: ['./factory.component.scss'],
  standalone: true,
  imports: [
    CommonModule,
    ReactiveFormsModule,
    MatFormFieldModule,
    MatInputModule,
    MatDatepickerModule,
    MatNativeDateModule,
    MatButtonModule,
    MatIconModule,
    MatSelectModule,
    MatAutocompleteModule,
    MatSnackBarModule
  ]
})
export class FactoryComponent implements OnInit {
  factoryForm: FormGroup;
  /** Searchable factory field (value is string while typing, or FactoryListRow when picked). */
  factorySearchCtrl = new FormControl<string | FactoryListRow>('');
  filteredFactories$: Observable<FactoryListRow[]>;

  prodOrders: FactoryProdOrderRow[] = [];
  factories: FactoryListRow[] = [];
  loadingList = false;
  loadingFactories = false;
  saving = false;
  isVendor = false;
  private vendorFactoryId: number | null = null;
  /** Total production orders matching filters (getProdOrderHeader-style pagination). */
  prodOrderTotalCount = 0;

  readonly displayFactoryFn = (v: FactoryListRow | string | null): string => {
    if (v == null) {
      return '';
    }
    if (typeof v === 'string') {
      return v;
    }
    return this.factoryLabel(v);
  };

  constructor(
    private fb: FormBuilder,
    private tracking: TrackingService,
    private coreApi: itemService,
    private snackBar: MatSnackBar
  ) {
    this.factoryForm = this.fb.group({
      factoryId: [null as number | null, Validators.required],
      prodOrderId: [null as number | null, Validators.required],
      materialArrivalDate: [null as Date | null],
      massProdStartDate: [null as Date | null],
      assemblyStartDate: [null as Date | null],
      actualProdComplete: [null as Date | null],
      packingStartDate: [null as Date | null],
      qcInspectionDate: [null as Date | null],
      actualEtd: [null as Date | null]
    });

    this.filteredFactories$ = this.factorySearchCtrl.valueChanges.pipe(
      startWith(''),
      map((value) => this.filterFactoryList(this.factorySearchQueryFromValue(value)))
    );
  }

  ngOnInit(): void {
    this.readTokenContext();
    this.loadingFactories = true;
    this.coreApi.listFactories().subscribe({
      next: (list) => {
        const full = list || [];
        if (this.isVendor) {
          if (this.vendorFactoryId != null) {
            this.factories = full.filter((f) => f.id === this.vendorFactoryId);
          } else {
            this.factories = [];
          }
        } else {
          this.factories = full;
        }
        this.loadingFactories = false;
        this.applyVendorFactoryPreset();
        this.applyFactorySearchDisabledState();
        this.loadOrders();
      },
      error: () => {
        this.loadingFactories = false;
        this.applyFactorySearchDisabledState();
        this.snackBar.open('Could not load factories', 'Dismiss', { duration: 5000 });
        this.loadOrders();
      }
    });
  }

  private applyFactorySearchDisabledState(): void {
    if (this.loadingFactories || (this.isVendor && this.factories.length <= 1)) {
      this.factorySearchCtrl.disable({ emitEvent: false });
    } else {
      this.factorySearchCtrl.enable({ emitEvent: false });
    }
  }

  private factorySearchQueryFromValue(value: string | FactoryListRow | null): string {
    if (value == null) {
      return '';
    }
    if (typeof value === 'string') {
      return value;
    }
    return this.factoryLabel(value);
  }

  private filterFactoryList(query: string): FactoryListRow[] {
    const q = query.trim().toLowerCase();
    if (!q) {
      return [...this.factories];
    }
    return this.factories.filter((f) => {
      const label = this.factoryLabel(f).toLowerCase();
      const name = (f.factory_name || '').toLowerCase();
      const nick = (f.factory_nickname || '').toLowerCase();
      return (
        label.includes(q) ||
        name.includes(q) ||
        nick.includes(q) ||
        String(f.id).includes(q)
      );
    });
  }

  private setFactorySelection(f: FactoryListRow | null): void {
    if (!f) {
      this.factoryForm.patchValue({ factoryId: null }, { emitEvent: false });
      this.factorySearchCtrl.setValue('', { emitEvent: false });
      return;
    }
    this.factoryForm.patchValue({ factoryId: f.id }, { emitEvent: false });
    this.factorySearchCtrl.setValue(f, { emitEvent: false });
  }

  onFactoryOptionSelected(event: MatAutocompleteSelectedEvent): void {
    const f = event.option.value as FactoryListRow;
    if (f) {
      this.setFactorySelection(f);
      this.onFactoryChange();
    }
  }

  onFactorySearchBlur(): void {
    const raw = this.factorySearchCtrl.value;
    const q = this.factorySearchQueryFromValue(raw).trim();
    const id = this.factoryForm.get('factoryId')?.value;
    const selected = id != null ? this.factories.find((x) => x.id === id) : null;
    if (selected && this.factoryLabel(selected) === q) {
      return;
    }
    const exact =
      q === ''
        ? null
        : this.factories.find((x) => this.factoryLabel(x) === q);
    if (exact) {
      this.setFactorySelection(exact);
      this.onFactoryChange();
    } else {
      this.setFactorySelection(null);
      this.loadOrders();
    }
  }

  private readTokenContext(): void {
    try {
      const token = localStorage.getItem('token');
      if (!token) {
        return;
      }
      const p = decode(token) as { role?: string; factory_id?: number };
      this.isVendor = p.role === 'vendor';
      if (p.role === 'vendor' && p.factory_id != null && !Number.isNaN(Number(p.factory_id))) {
        this.vendorFactoryId = Number(p.factory_id);
      }
    } catch {
      /* ignore */
    }
  }

  private applyVendorFactoryPreset(): void {
    if (this.isVendor && this.vendorFactoryId != null && this.factories.some((f) => f.id === this.vendorFactoryId)) {
      const f = this.factories.find((x) => x.id === this.vendorFactoryId)!;
      this.setFactorySelection(f);
    }
  }

  loadOrders(): void {
    const fid = this.factoryForm.get('factoryId')?.value;
    if (fid === null || fid === undefined) {
      this.prodOrders = [];
      this.prodOrderTotalCount = 0;
      this.factoryForm.patchValue({
        prodOrderId: null,
        materialArrivalDate: null,
        massProdStartDate: null,
        assemblyStartDate: null,
        actualProdComplete: null,
        packingStartDate: null,
        qcInspectionDate: null,
        actualEtd: null
      });
      if (!this.factorySearchQueryFromValue(this.factorySearchCtrl.value).trim()) {
        this.factorySearchCtrl.setValue('', { emitEvent: false });
      }
      this.loadingList = false;
      return;
    }

    this.loadingList = true;
    const factoryIdParam = Number(fid);
    const startRow = 0;
    const endRow = 10000;

    this.tracking
      .getFactoryProdOrderList(factoryIdParam, {
        startRow,
        endRow,
        filterModel: {}
      })
      .subscribe({
      next: (res: { rows?: FactoryProdOrderRow[]; totalCount?: number }) => {
        this.prodOrders = res?.rows || [];
        this.prodOrderTotalCount = res?.totalCount ?? this.prodOrders.length;
        this.loadingList = false;
        this.factoryForm.patchValue({
          prodOrderId: null,
          materialArrivalDate: null,
          massProdStartDate: null,
          assemblyStartDate: null,
          actualProdComplete: null,
          packingStartDate: null,
          qcInspectionDate: null,
          actualEtd: null
        });
      },
      error: () => {
        this.loadingList = false;
        this.snackBar.open('Could not load production orders', 'Dismiss', { duration: 5000 });
      }
    });
  }

  onFactoryChange(): void {
    this.factoryForm.patchValue({
      prodOrderId: null,
      materialArrivalDate: null,
      massProdStartDate: null,
      assemblyStartDate: null,
      actualProdComplete: null,
      packingStartDate: null,
      qcInspectionDate: null,
      actualEtd: null
    });
    this.loadOrders();
  }

  factoryLabel(f: FactoryListRow): string {
    return (f.factory_name || f.factory_nickname || `Factory #${f.id}`).trim();
  }

  /** Dropdown label: prod reference (business key), same field prod tracking uses; fallback for legacy rows. */
  productionOrderLabel(o: FactoryProdOrderRow): string {
    const ref = (o.prodReferenceNo || '').trim();
    if (ref) {
      return ref;
    }
    const po = (o.prodOrderNo || '').trim();
    if (po) {
      return po;
    }
    return `Order #${o.id}`;
  }

  onProductionOrderChange(): void {
    const id = this.factoryForm.get('prodOrderId')?.value;
    const row = this.prodOrders.find((o) => o.id === id);
    if (!row) {
      return;
    }
    this.factoryForm.patchValue({
      materialArrivalDate: this.parseYmd(row.material_arrival_date),
      massProdStartDate: this.parseYmd(row.mass_prod_start_date),
      assemblyStartDate: this.parseYmd(row.assembly_start_date),
      actualProdComplete: this.parseYmd(row.actual_prod_complete),
      packingStartDate: this.parseYmd(row.packing_start_date),
      qcInspectionDate: this.parseYmd(row.qc_inspection_date),
      actualEtd: this.parseYmd(row.actual_etd)
    });
  }

  private parseYmd(value: string | null | undefined): Date | null {
    if (!value) {
      return null;
    }
    const m = String(value).match(/^(\d{4})-(\d{2})-(\d{2})/);
    if (!m) {
      return null;
    }
    const y = Number(m[1]);
    const mo = Number(m[2]) - 1;
    const d = Number(m[3]);
    return new Date(y, mo, d);
  }

  private fmtYmd(d: Date | null | undefined): string | null {
    if (!d) {
      return null;
    }
    const yyyy = d.getFullYear();
    const mm = String(d.getMonth() + 1).padStart(2, '0');
    const dd = String(d.getDate()).padStart(2, '0');
    return `${yyyy}-${mm}-${dd}`;
  }

  onSave(): void {
    if (this.factoryForm.invalid) {
      this.factoryForm.markAllAsTouched();
      const msg =
        this.factoryForm.get('factoryId')?.invalid
          ? 'Select a factory'
          : 'Select a production order';
      this.snackBar.open(msg, 'Dismiss', { duration: 4000 });
      return;
    }
    const v = this.factoryForm.getRawValue();
    this.saving = true;
    this.tracking
      .updateFactoryProdOrderDates({
        id: v.prodOrderId,
        material_arrival_date: this.fmtYmd(v.materialArrivalDate),
        mass_prod_start_date: this.fmtYmd(v.massProdStartDate),
        assembly_start_date: this.fmtYmd(v.assemblyStartDate),
        actual_prod_complete: this.fmtYmd(v.actualProdComplete),
        packing_start_date: this.fmtYmd(v.packingStartDate),
        qc_inspection_date: this.fmtYmd(v.qcInspectionDate),
        actual_etd: this.fmtYmd(v.actualEtd)
      })
      .subscribe({
        next: () => {
          this.saving = false;
          this.snackBar.open('Saved', 'Dismiss', { duration: 3000 });
          const id = v.prodOrderId;
          const row = this.prodOrders.find((o) => o.id === id);
          if (row) {
            row.material_arrival_date = this.fmtYmd(v.materialArrivalDate);
            row.mass_prod_start_date = this.fmtYmd(v.massProdStartDate);
            row.assembly_start_date = this.fmtYmd(v.assemblyStartDate);
            row.actual_prod_complete = this.fmtYmd(v.actualProdComplete);
            row.packing_start_date = this.fmtYmd(v.packingStartDate);
            row.qc_inspection_date = this.fmtYmd(v.qcInspectionDate);
            row.actual_etd = this.fmtYmd(v.actualEtd);
          }
        },
        error: (err) => {
          this.saving = false;
          const msg = err?.error?.message || 'Save failed';
          this.snackBar.open(msg, 'Dismiss', { duration: 6000 });
        }
      });
  }
}

