const sql = require('./db');
const Sequelize = require('sequelize');
const { Op } = require('sequelize');
const { getUserInfo } = require('../helpers/auth');
const status = require('../helpers/sampleStatus');

const Sample = {};

// Columns a client is allowed to filter the grid on (whitelist guards against
// AG Grid sending a colId that is not a real column).
const FILTERABLE = new Set([
  'sample_id_pk', 'origin', 'direction', 'sample_name', 'quantity',
  'retail_price', 'fob_cost', 'factory_id_fk', 'factory_group_id_fk',
  'box_id_fk', 'status', 'office_location', 'notes',
  'item_id_fk', 'prod_order_no_fk'
]);

// Columns a client is allowed to set/update (status moves go through events).
const EDITABLE = [
  'sample_name', 'quantity', 'retail_price', 'fob_cost',
  'factory_id_fk', 'factory_group_id_fk', 'box_id_fk', 'office_location', 'notes',
  'item_id_fk', 'prod_order_no_fk'
];

// Translate one AG Grid filter definition into a Sequelize condition.
// Mirrors the buildCondition logic used in lic.model.js.
const buildCondition = (filterDef) => {
  if (!filterDef) return null;

  if (filterDef.filterType === 'date') {
    const { type, dateFrom, dateTo } = filterDef;
    if (!dateFrom) return null;
    const startOfDay = new Date(dateFrom);
    startOfDay.setHours(0, 0, 0, 0);
    const endOfDay = new Date(startOfDay);
    endOfDay.setHours(23, 59, 59, 999);
    switch (type) {
      case 'equals': return { [Op.between]: [startOfDay, endOfDay] };
      case 'notEqual': return { [Op.notBetween]: [startOfDay, endOfDay] };
      case 'lessThan': return { [Op.lt]: startOfDay };
      case 'greaterThan': return { [Op.gt]: startOfDay };
      case 'inRange': {
        if (!dateTo) return null;
        const rangeEnd = new Date(dateTo);
        rangeEnd.setHours(23, 59, 59, 999);
        return { [Op.between]: [startOfDay, rangeEnd] };
      }
      default: return null;
    }
  }

  if (filterDef.filterType === 'number') {
    const n = filterDef.filter;
    switch (filterDef.type) {
      case 'equals': return { [Op.eq]: n };
      case 'notEqual': return { [Op.ne]: n };
      case 'lessThan': return { [Op.lt]: n };
      case 'lessThanOrEqual': return { [Op.lte]: n };
      case 'greaterThan': return { [Op.gt]: n };
      case 'greaterThanOrEqual': return { [Op.gte]: n };
      case 'inRange': return { [Op.between]: [n, filterDef.filterTo] };
      default: return null;
    }
  }

  // default: text
  const value = typeof filterDef.filter === 'string' ? filterDef.filter : '';
  switch (filterDef.type) {
    case 'contains': return { [Op.iLike]: `%${value}%` };
    case 'notContains': return { [Op.notILike]: `%${value}%` };
    case 'equals': return { [Op.eq]: filterDef.filter };
    case 'notEqual': return { [Op.ne]: filterDef.filter };
    case 'startsWith': return { [Op.iLike]: `${value}%` };
    case 'endsWith': return { [Op.iLike]: `%${value}` };
    case 'blank': return { [Op.or]: [{ [Op.eq]: null }, { [Op.eq]: '' }] };
    case 'notBlank': return { [Op.and]: [{ [Op.ne]: null }, { [Op.ne]: '' }] };
    default: return null;
  }
};

// Server-side grid contract: ?startRow&endRow&filterModel -> { rows, totalCount }
Sample.list = async (req, result) => {
  const { startRow, endRow, filterModel } = req.query;
  const limit = endRow != null && startRow != null ? Number(endRow) - Number(startRow) : 100;
  const offset = startRow != null ? Number(startRow) : 0;

  try {
    const filters = filterModel ? JSON.parse(filterModel) : {};
    const whereClause = {};

    Object.entries(filters).forEach(([field, filterDef]) => {
      if (!FILTERABLE.has(field)) return;
      // Normalise AG Grid "multi" filters the same way lic.model does.
      let def = filterDef;
      if (def && def.filterType === 'multi') {
        def = (def.filterModels || []).find(sub => sub) || null;
      }
      const condition = buildCondition(def);
      if (condition) whereClause[field] = condition;
    });

    const { count, rows } = await sql.sample.findAndCountAll({
      where: whereClause,
      order: [['sample_id_pk', 'DESC']],
      limit,
      offset,
      distinct: true,
      include: sql.sample_attachment
        ? [{ model: sql.sample_attachment, as: 'sampleAttachments', required: false }]
        : []
    });

    // Surface a primary_photo thumbnail URL on each row for the grid.
    const mapped = rows.map(r => {
      const plain = (r && typeof r.get === 'function') ? r.get({ plain: true }) : r;
      const atts = (plain && plain.sampleAttachments) || [];
      const primary = atts.find(a => a.primary_image) || atts[0];
      plain.primary_photo = primary ? primary.attachment_link : null;
      return plain;
    });

    // Surface the box label (so the grid shows which box a sample is in).
    const boxIds = [...new Set(mapped.map(r => r.box_id_fk).filter(Boolean))];
    if (boxIds.length && sql.sample_box) {
      const boxes = await sql.sample_box.findAll({ where: { box_id_pk: { [Op.in]: boxIds } } });
      const labels = new Map(boxes.map(b => [b.box_id_pk, b.box_label]));
      mapped.forEach(r => {
        r.box_label = r.box_id_fk ? (labels.get(r.box_id_fk) || `Box #${r.box_id_fk}`) : null;
      });
    } else {
      mapped.forEach(r => { r.box_label = null; });
    }

    return result(null, { rows: mapped, totalCount: count });
  } catch (err) {
    console.error('Sample.list error', err);
    return result(err);
  }
};

Sample.getById = async (req, result) => {
  try {
    const row = await sql.sample.findByPk(Number(req.params.id), {
      include: [{ model: sql.sample_event, as: 'events', required: false }]
    });
    if (!row) return result({ status: 404, message: 'Sample not found' });
    return result(null, row);
  } catch (err) {
    console.error('Sample.getById error', err);
    return result(err);
  }
};

Sample.create = async (req, result) => {
  try {
    const user = await getUserInfo(req.headers.authorization);
    const body = req.body || {};
    const origin = body.origin;

    if (!status.ORIGINS.includes(origin)) {
      return result({ status: 400, message: `origin must be one of ${status.ORIGINS.join(', ')}` });
    }
    const def = status.ORIGIN_DEFAULTS[origin];
    const now = String(Date.now());

    const payload = {
      origin,
      direction: def.direction,
      status: def.initialStatus,
      sample_name: body.sample_name ?? null,
      quantity: body.quantity ?? null,
      retail_price: body.retail_price ?? null,
      fob_cost: body.fob_cost ?? null,
      factory_id_fk: body.factory_id_fk ?? null,
      item_id_fk: body.item_id_fk ?? null,
      prod_order_no_fk: body.prod_order_no_fk ?? null,
      factory_group_id_fk: body.factory_group_id_fk ?? null,
      box_id_fk: body.box_id_fk ?? null,
      office_location: body.office_location ?? null,
      notes: body.notes ?? null,
      sample_createdUser: user?.name ?? null,
      sample_createdTime: now,
      sample_modUser: user?.name ?? null,
      sample_modTime: now
    };

    const row = await sql.sample.create(payload);

    // Initial lifecycle event so the timeline always starts with creation.
    await sql.sample_event.create({
      sample_id_fk: row.sample_id_pk,
      event_type: 'status_change',
      from_status: null,
      to_status: def.initialStatus,
      office_location: payload.office_location,
      event_user_id_fk: user?.user_id ?? null,
      event_user: user?.name ?? null,
      event_time: new Date(),
      notes: 'Sample created'
    });

    return result(null, row);
  } catch (err) {
    console.error('Sample.create error', err);
    return result(err);
  }
};

Sample.update = async (req, result) => {
  try {
    const user = await getUserInfo(req.headers.authorization);
    const id = Number(req.params.id);
    const body = req.body || {};

    if ('status' in body || 'direction' in body || 'origin' in body) {
      return result({ status: 400, message: 'status/direction/origin are not directly editable; use /sample/events' });
    }

    const values = {};
    EDITABLE.forEach(col => { if (col in body) values[col] = body[col]; });
    if (Object.keys(values).length === 0) {
      return result({ status: 400, message: 'No editable fields supplied' });
    }
    values.sample_modUser = user?.name ?? null;
    values.sample_modTime = String(Date.now());

    const [affected] = await sql.sample.update(values, { where: { sample_id_pk: id } });
    if (!affected) return result({ status: 404, message: 'Sample not found' });

    const row = await sql.sample.findByPk(id);
    return result(null, row);
  } catch (err) {
    console.error('Sample.update error', err);
    return result(err);
  }
};

Sample.remove = async (req, result) => {
  try {
    const id = Number(req.params.id);
    // FKs are not DB-enforced, so cascade integrity is owned here.
    await sql.sample_event.destroy({ where: { sample_id_fk: id } });
    // Attachments / comments / shipment-items are introduced in PR-2; guard so
    // this keeps working before those models exist.
    if (sql.sample_attachment) await sql.sample_attachment.destroy({ where: { sample_id_fk: id } });
    if (sql.sample_comments) await sql.sample_comments.destroy({ where: { sample_id_fk: id } });
    if (sql.sample_shipment_item) await sql.sample_shipment_item.destroy({ where: { sample_id_fk: id } });

    const deleted = await sql.sample.destroy({ where: { sample_id_pk: id } });
    if (!deleted) return result({ status: 404, message: 'Sample not found' });
    return result(null, { sample_id: id, deleted: true });
  } catch (err) {
    console.error('Sample.remove error', err);
    return result(err);
  }
};

/**
 * The bidirectional check-in/out engine. The client supplies event_type +
 * office_location (+ optional notes, + to_status only for status_change). The
 * resulting backbone status is DERIVED here and written under an optimistic
 * guard so two concurrent moves from the same status cannot both succeed.
 */
Sample.recordEvent = async (req, result) => {
  try {
    const user = await getUserInfo(req.headers.authorization);
    const body = req.body || {};
    const sampleId = Number(body.sample_id_fk || req.params.id);
    const eventType = body.event_type;
    const office = body.office_location ?? null;
    const notes = body.notes ?? null;
    const requestedToStatus = body.to_status ?? null;

    if (!sampleId) return result({ status: 400, message: 'sample_id_fk is required' });

    const sample = await sql.sample.findByPk(sampleId);
    if (!sample) return result({ status: 404, message: 'Sample not found' });

    const fromStatus = sample.status;
    const derived = status.deriveToStatus({
      direction: sample.direction,
      currentStatus: fromStatus,
      office,
      eventType,
      requestedToStatus
    });
    if (!derived.ok) return result({ status: derived.status, message: derived.error });

    // Optimistic concurrency: only advance if the row is still in fromStatus.
    const [affected] = await sql.sample.update(
      {
        status: derived.toStatus,
        office_location: office ?? sample.office_location,
        sample_modUser: user?.name ?? null,
        sample_modTime: String(Date.now())
      },
      { where: { sample_id_pk: sampleId, status: fromStatus } }
    );
    if (!affected) {
      return result({ status: 409, message: 'Sample status changed concurrently; please retry' });
    }

    const event = await sql.sample_event.create({
      sample_id_fk: sampleId,
      event_type: eventType,
      from_status: fromStatus,
      to_status: derived.toStatus,
      office_location: office,
      event_user_id_fk: user?.user_id ?? null,
      event_user: user?.name ?? null,
      event_time: new Date(),
      notes
    });

    return result(null, {
      sample_id: sampleId,
      from_status: fromStatus,
      to_status: derived.toStatus,
      event
    });
  } catch (err) {
    console.error('Sample.recordEvent error', err);
    return result(err);
  }
};

Sample.listEvents = async (req, result) => {
