'use strict';
/**
 * Sample status state machine — single source of truth for the sample lifecycle.
 *
 * A sample travels in one of two directions:
 *   inbound  (factory-origin): requested -> shipped -> ningbo_checked_in
 *                              -> ningbo_checked_out -> nyc_checked_in
 *   outbound (usa-bought):     nyc_requested -> nyc_checked_out -> ningbo_checked_in
 *                              -> ningbo_checked_out -> sent_to_factory
 *
 * Backbone moves (check_in / check_out / ship) have their resulting status
 * DERIVED from (direction, current status, office, event_type) — the client
 * never supplies the target status for those. The "shared extra" states
 * (cancelled / on_hold / damaged / approved) are reached with a status_change
 * event whose requested target is validated against a small allow-list.
 */

const ORIGINS = ['factory_request', 'factory_offer', 'usa_bought'];
const DIRECTIONS = ['inbound', 'outbound'];
const OFFICES = ['Ningbo', 'NYC'];
const EVENT_TYPES = ['check_in', 'check_out', 'ship', 'receive', 'status_change'];

// Shared exception states reachable (almost) any time.
const SHARED_EXTRAS = ['cancelled', 'on_hold', 'damaged', 'approved'];
// Once here, no further moves are allowed.
const TERMINAL_EXTRAS = ['cancelled'];

// Origin -> how a freshly created sample starts.
const ORIGIN_DEFAULTS = {
  factory_request: { direction: 'inbound', initialStatus: 'requested' },
  factory_offer: { direction: 'inbound', initialStatus: 'requested' },
  usa_bought: { direction: 'outbound', initialStatus: 'nyc_requested' }
};

// Ordered backbone status lists per direction (used for resume-from-hold).
const BACKBONE = {
  inbound: ['requested', 'shipped', 'ningbo_checked_in', 'ningbo_checked_out', 'nyc_checked_in'],
  outbound: ['nyc_requested', 'nyc_checked_out', 'ningbo_checked_in', 'ningbo_checked_out', 'sent_to_factory']
};

// Backbone transition rules. `office: null` means the office is not checked.
const TRANSITIONS = {
  inbound: [
    { from: 'requested', eventType: 'ship', office: null, to: 'shipped' },
    { from: 'shipped', eventType: 'check_in', office: 'Ningbo', to: 'ningbo_checked_in' },
    { from: 'ningbo_checked_in', eventType: 'check_out', office: 'Ningbo', to: 'ningbo_checked_out' },
    { from: 'ningbo_checked_out', eventType: 'check_in', office: 'NYC', to: 'nyc_checked_in' }
  ],
  outbound: [
    { from: 'nyc_requested', eventType: 'check_out', office: 'NYC', to: 'nyc_checked_out' },
    { from: 'nyc_checked_out', eventType: 'check_in', office: 'Ningbo', to: 'ningbo_checked_in' },
    { from: 'ningbo_checked_in', eventType: 'check_out', office: 'Ningbo', to: 'ningbo_checked_out' },
    { from: 'ningbo_checked_out', eventType: 'ship', office: 'Ningbo', to: 'sent_to_factory' }
  ]
};

// All statuses that can ever appear, for validation/migration assertions.
const ALL_STATUSES = Array.from(new Set([
  ...BACKBONE.inbound,
  ...BACKBONE.outbound,
  ...SHARED_EXTRAS
]));

function isBackboneStatus(direction, status) {
  return (BACKBONE[direction] || []).includes(status);
}

/**
 * Derive the resulting status for an event, or explain why it is rejected.
 * @returns {{ ok: true, toStatus: string }
 *          | { ok: false, status: number, error: string }}
 */
function deriveToStatus({ direction, currentStatus, office, eventType, requestedToStatus }) {
  if (!DIRECTIONS.includes(direction)) {
    return { ok: false, status: 400, error: `Unknown direction "${direction}"` };
  }
  if (!EVENT_TYPES.includes(eventType)) {
    return { ok: false, status: 400, error: `Unknown event_type "${eventType}"` };
  }
  if (TERMINAL_EXTRAS.includes(currentStatus)) {
    return { ok: false, status: 409, error: `Sample is ${currentStatus}; no further changes allowed` };
  }

  // Shared-extra / resume moves go through status_change.
  if (eventType === 'status_change') {
    if (!requestedToStatus) {
      return { ok: false, status: 400, error: 'status_change requires a to_status' };
    }
    if (SHARED_EXTRAS.includes(requestedToStatus)) {
      if (requestedToStatus === currentStatus) {
        return { ok: false, status: 409, error: `Sample already ${currentStatus}` };
      }
      return { ok: true, toStatus: requestedToStatus };
    }
    // Resume from on_hold back onto the backbone.
    if (currentStatus === 'on_hold' && isBackboneStatus(direction, requestedToStatus)) {
      return { ok: true, toStatus: requestedToStatus };
    }
    return { ok: false, status: 400, error: `Illegal status_change to "${requestedToStatus}" from "${currentStatus}"` };
  }

  // Backbone moves: look up the single matching rule.
  const rule = (TRANSITIONS[direction] || []).find(r =>
    r.from === currentStatus &&
    r.eventType === eventType &&
    (r.office === null || r.office === office)
  );
  if (!rule) {
    return {
      ok: false,
      status: 400,
      error: `No ${eventType} transition from "${currentStatus}"` +
        (office ? ` at ${office}` : '') + ` for ${direction} sample`
    };
  }
  return { ok: true, toStatus: rule.to };
}

module.exports = {
  ORIGINS,
  DIRECTIONS,
  OFFICES,
  EVENT_TYPES,
  SHARED_EXTRAS,
  TERMINAL_EXTRAS,
  ORIGIN_DEFAULTS,
  BACKBONE,
  TRANSITIONS,
  ALL_STATUSES,
  isBackboneStatus,
  deriveToStatus
};

