// Column config for the Sample Tracking grid skin. Mirrors the addColumn /
// commonDefaults factory used by the other tracking grids (e.g.
// license.tracking.config.ts) so the look matches the existing screens.

import { directionLabel } from '../../pages/sample_tracking/helpers/sample.status';

export const SAMPLE_TRACKING_COLUMN_HEADERS_CONFIG: any = {
  columnDefs: getSampleTrackingColumnDefs()
};

function getSampleTrackingColumnDefs() {
  const commonDefaults = {
    filter: 'agTextColumnFilter',
    floatingFilter: true,
    sortable: true,
    editable: false,
    hide: false,
    checkboxSelection: false,
    rowDrag: false,
    rowGroup: false,
    cellStyle: { 'text-align': 'center' }
  };

  const addColumn = (
    headerName: string,
    field: string,
    colId: string,
    width: number,
    overrides: any = {}
  ) => ({
    headerName,
    field,
    colId,
    col_id: colId, // keep both for backwards-compat with the layout system
    width,
    ...commonDefaults,
    ...overrides
  });

  return [
    addColumn('Photo', 'primary_photo', 'primary_photo', 90, {
      cellRenderer: 'samplePhotoRenderer',
      editable: false,
      filter: false,
      floatingFilter: false,
      sortable: false
    }),
    // expand/collapse for the master-detail (event timeline + comments)
    addColumn('Sample', 'sample_name', 'sample_name', 220, {
      cellRenderer: 'agGroupCellRenderer',
      editable: true
    }),
    addColumn('Status', 'status', 'status', 180, {
      cellRenderer: 'sampleStatusRenderer',
      editable: false
    }),
    addColumn('Office', 'office_location', 'office_location', 110),
    addColumn('Box', 'box_label', 'box_label', 130),
    addColumn('Origin', 'origin', 'origin', 140, {
      filter: 'agSetColumnFilter'
    }),
    addColumn('Journey', 'direction', 'direction', 130, {
      valueFormatter: (p: any) => directionLabel(p.value)
    }),
    addColumn('Qty', 'quantity', 'quantity', 90, {
      filter: 'agNumberColumnFilter',
      editable: true,
      type: 'numericColumn'
    }),
    addColumn('Retail', 'retail_price', 'retail_price', 110, {
      filter: 'agNumberColumnFilter',
      editable: true,
      type: 'numericColumn',
      valueFormatter: moneyFormatter
    }),
    addColumn('FOB Cost', 'fob_cost', 'fob_cost', 110, {
      filter: 'agNumberColumnFilter',
      editable: true,
      type: 'numericColumn',
      valueFormatter: moneyFormatter
    }),
    addColumn('Factory', 'factory_id_fk', 'factory_id_fk', 110, {
      filter: 'agNumberColumnFilter'
    }),
    addColumn('Linked Item', 'item_id_fk', 'item_id_fk', 120, {
      filter: 'agNumberColumnFilter'
    }),
    addColumn('Prod Order', 'prod_order_no_fk', 'prod_order_no_fk', 130),
    addColumn('Notes', 'notes', 'notes', 240, { editable: true })
  ];
}

function moneyFormatter(params: any): string {
  const v = params && params.value;
  if (v === null || v === undefined || v === '') return '';
  const n = Number(v);
  return isNaN(n) ? String(v) : `$${n.toFixed(2)}`;
}

